import React, { useState } from 'react';
import '../styles/Challenges.css';

const parseReward = (rewardStr) => {
  const xpMatch = rewardStr.match(/(\d+)\s*XP/);
  const xp = xpMatch ? parseInt(xpMatch[1]) : 0;
  const coins = Math.max(5, Math.round(xp * 0.2));
  return { xp, coins };
};

const dailyChallenges = [
  {
    title: 'Walk 10,000 steps today',
    reward: '50 XP +5 Energy',
    barEffects: { energy: 5 },
    effectLabel: '+5 Energy',
  },
  {
    title: 'Drink 2L of water',
    reward: '20 XP +3 HP',
    barEffects: { hp: 3 },
    effectLabel: '+3 HP',
  },
  {
    title: 'No Sugary snacks',
    reward: '30 XP +3 Discipline',
    barEffects: { discipline: 3 },
    effectLabel: '+3 Discipline',
  },
  {
    title: 'Morning Stretch',
    reward: '15 XP +2 Energy',
    barEffects: { energy: 2 },
    effectLabel: '+2 Energy',
  },
  {
    title: 'Daily Workout Complete',
    reward: '50 XP +5 Energy +2 Discipline',
    barEffects: { energy: 5, discipline: 2 },
    effectLabel: '+5 Energy +2 Discipline',
  },
];

const weeklyChallenges = [
  { title: 'Run a total distance of 20 km in a week', progress: 40,  reward: '150 XP +50 Energy' },
  { title: 'Share progress with a friend',            progress: 100, reward: '60 XP +20 Energy'  },
  { title: 'Sleep 7-8 hours per night for 5 nights', progress: 70,  reward: '120 XP +40 Energy' },
  { title: 'Drink 14L water total this week',         progress: 60,  reward: '100 XP +30 Energy' },
];

const Challenges = ({ onChallengeComplete }) => {
  const [dailyChecked, setDailyChecked] = useState({});
  const [flash, setFlash] = useState(null); // show reward flash

  const handleCheck = (index) => {
    if (dailyChecked[index]) return;
    const challenge = dailyChallenges[index];
    setDailyChecked(prev => ({ ...prev, [index]: true }));
    const { xp, coins } = parseReward(challenge.reward);
    if (onChallengeComplete) onChallengeComplete(xp, coins, challenge.barEffects);

    // Flash reward message
    setFlash({ label: `+${xp} XP  ${challenge.effectLabel}`, index });
    setTimeout(() => setFlash(null), 2000);
  };

  return (
    <div className="page-container">
      <div className="challenges-grid">

        {/* Daily Challenges */}
        <div className="card challenges-card" data-testid="daily-challenges">
          <h2 className="section-title">Daily Challenges</h2>
          <div className="challenge-list">
            {dailyChallenges.map((challenge, index) => (
              <div
                key={index}
                className={`challenge-item daily ${dailyChecked[index] ? 'completed' : ''}`}
                data-testid={`daily-challenge-${index}`}
              >
                <div className="challenge-content">
                  <span className="challenge-title">{challenge.title}</span>
                  <div className="challenge-reward">
                    <span className="reward-icon">🪙</span>
                    <span>{challenge.reward}</span>
                    {/* Flash popup */}
                    {flash && flash.index === index && (
                      <span className="reward-flash">{flash.label}</span>
                    )}
                  </div>
                </div>
                <input
                  type="checkbox"
                  className="challenge-checkbox"
                  checked={!!dailyChecked[index]}
                  onChange={() => handleCheck(index)}
                  data-testid={`daily-checkbox-${index}`}
                />
              </div>
            ))}
          </div>
        </div>

        {/* Weekly Challenges */}
        <div className="card challenges-card" data-testid="weekly-challenges">
          <h2 className="section-title">Weekly Challenges</h2>
          <div className="challenge-list">
            {weeklyChallenges.map((challenge, index) => (
              <div key={index} className="challenge-item weekly" data-testid={`weekly-challenge-${index}`}>
                <div className="challenge-header">
                  <span className="challenge-title">{challenge.title}</span>
                </div>
                <div className="progress-container">
                  <div className="progress-bar-wrapper">
                    <div className="progress-bar-fill" style={{width:`${challenge.progress}%`}} />
                  </div>
                  <div className="challenge-reward-weekly">
                    <span className="reward-icon-weekly">⚡</span>
                    <span>{challenge.reward}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

      </div>
    </div>
  );
};

export default Challenges;
